/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Data Freshness Indicator
   Shows "Updated Xs ago", "Live" with pulse dot, or staleness warnings.
   - Green pulse dot when < 60s (live)
   - Amber after 60s
   - Red after 300s

   Usage:
     <DataFreshness lastUpdated={Date.now()} label="Positions" />
     <DataFreshness lastUpdated={timestamp} />
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect } from 'react';

const FRESH_THRESHOLD = 60_000;    // 60 seconds
const STALE_THRESHOLD = 300_000;   // 5 minutes

const COLORS = {
  live:  '#3FB950',
  amber: '#D29922',
  red:   '#F85149',
  text:  '#8B949E',
};

// Inject pulse keyframes once
let pulseCSSInjected = false;
function injectPulseCSS() {
  if (pulseCSSInjected || typeof document === 'undefined') return;
  pulseCSSInjected = true;
  const style = document.createElement('style');
  style.textContent = `
    @keyframes aura-freshness-pulse {
      0%, 100% { opacity: 1; }
      50% { opacity: 0.4; }
    }
  `;
  document.head.appendChild(style);
}

function formatAge(ms) {
  if (ms < 1000) return 'just now';
  const secs = Math.floor(ms / 1000);
  if (secs < 60) return `${secs}s ago`;
  const mins = Math.floor(secs / 60);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  return `${hrs}h ago`;
}

export default function DataFreshness({ lastUpdated, label, style: outerStyle = {} }) {
  const [now, setNow] = useState(Date.now());

  useEffect(() => {
    const iv = setInterval(() => setNow(Date.now()), 2000);
    return () => clearInterval(iv);
  }, []);

  injectPulseCSS();

  if (!lastUpdated) return null;

  const age = now - lastUpdated;
  const isLive = age < FRESH_THRESHOLD;
  const isStale = age >= STALE_THRESHOLD;
  const color = isLive ? COLORS.live : isStale ? COLORS.red : COLORS.amber;
  const statusText = isLive ? 'Live' : `Updated ${formatAge(age)}`;

  return (
    <span
      title={label ? `${label}: ${statusText}` : statusText}
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: 6,
        fontSize: 11,
        fontWeight: 500,
        fontFamily: "'JetBrains Mono', monospace",
        color,
        padding: '3px 10px',
        borderRadius: 20,
        backgroundColor: `${color}12`,
        border: `1px solid ${color}30`,
        transition: 'all 200ms ease',
        whiteSpace: 'nowrap',
        userSelect: 'none',
        ...outerStyle,
      }}
    >
      {/* Pulse dot */}
      <span
        style={{
          width: 6,
          height: 6,
          borderRadius: '50%',
          backgroundColor: color,
          boxShadow: isLive ? `0 0 6px ${color}80` : 'none',
          animation: isLive ? 'aura-freshness-pulse 2s ease-in-out infinite' : 'none',
          flexShrink: 0,
        }}
      />
      {statusText}
    </span>
  );
}

/* ── Compact variant — just the dot, no text, for table headers ──────────── */
export function FreshnessDot({ lastUpdated, size = 6 }) {
  const [now, setNow] = useState(Date.now());
  useEffect(() => {
    const iv = setInterval(() => setNow(Date.now()), 2000);
    return () => clearInterval(iv);
  }, []);

  injectPulseCSS();

  if (!lastUpdated) return null;
  const age = now - lastUpdated;
  const isLive = age < FRESH_THRESHOLD;
  const isStale = age >= STALE_THRESHOLD;
  const color = isLive ? COLORS.live : isStale ? COLORS.red : COLORS.amber;

  return (
    <span
      title={isLive ? 'Live' : `Updated ${formatAge(age)}`}
      style={{
        display: 'inline-block',
        width: size,
        height: size,
        borderRadius: '50%',
        backgroundColor: color,
        boxShadow: isLive ? `0 0 4px ${color}80` : 'none',
        animation: isLive ? 'aura-freshness-pulse 2s ease-in-out infinite' : 'none',
        verticalAlign: 'middle',
        flexShrink: 0,
      }}
    />
  );
}
